script:
frappe.ui.form.on('Additional Salary', {
    refresh: function(frm) {
        // Skip Payment Button
        if (!frm.is_new()) {
            frm.add_custom_button(__('Skip Payment'), function() {
                let dialog = new frappe.ui.Dialog({
                    title: __('Skip Payment'),
                    fields: [
                        {
                            fieldtype: 'Int',
                            label: 'Enter number of months to skip',
                            fieldname: 'months_to_skip',
                            reqd: 1,
                            default: 1,
                            onchange: function() {
                                let monthsToSkip = dialog.get_value('months_to_skip');
                                if (monthsToSkip && monthsToSkip > 0) {
                                    // Calculate restart month
                                    let currentDate = new Date();
                                    currentDate.setDate(1);
                                    currentDate.setMonth(currentDate.getMonth() + monthsToSkip);

                                    let monthNames = ['January', 'February', 'March', 'April', 'May', 'June',
                                                     'July', 'August', 'September', 'October', 'November', 'December'];

                                    let restartMonth = monthNames[currentDate.getMonth()] + ' ' + currentDate.getFullYear();

                                    // Calculate new end date
                                    let currentToDate = new Date(frm.doc.to_date);
                                    currentToDate.setDate(1);
                                    currentToDate.setMonth(currentToDate.getMonth() + monthsToSkip);
                                    let lastDayOfToDate = new Date(currentToDate.getFullYear(), currentToDate.getMonth() + 1, 0);
                                    let newEndDate = frappe.datetime.str_to_user(frappe.datetime.obj_to_str(lastDayOfToDate));

                                    // Calculate financial impact
                                    let monthlyAmount = Math.abs(frm.doc.amount) || 0;
                                    let deferredAmount = monthlyAmount * monthsToSkip;

                                    // Update description with details
                                    dialog.fields_dict.months_to_skip.set_description(
                                        `<div style="background: #e8f5e9; padding: 10px; border-radius: 5px; margin-top: 10px;">
                                            <b style="color: #2e7d32;">📅 Repayment Details:</b><br>
                                            <span style="color: #1b5e20;">• Will restart from: <b>${restartMonth}</b></span><br>
                                            <span style="color: #1b5e20;">• New end date: <b>${newEndDate}</b></span><br>
                                            <span style="color: #1b5e20;">• Current skips: <b>${frm.doc.custom_times_skipped || 0}</b></span><br><br>
                                            <b style="color: #d32f2f;">💰 Financial Impact:</b><br>
                                            <span style="color: #c62828;">• Monthly payment: <b>${frappe.format(monthlyAmount, {fieldtype: 'Currency'})}</b></span><br>
                                            <span style="color: #c62828;">• Amount deferred: <b>${frappe.format(deferredAmount, {fieldtype: 'Currency'})}</b></span>
                                        </div>`
                                    );
                                } else {
                                    dialog.fields_dict.months_to_skip.set_description('');
                                }
                            }
                        },
                        {
                            fieldtype: 'Column Break'
                        },
                        {
                            fieldtype: 'Small Text',
                            label: 'Reason for Skip',
                            fieldname: 'skip_reason',
                            description: 'Optional: Document why this payment is being skipped'
                        }
                    ],
                    primary_action_label: __('Confirm Skip'),
                    primary_action: function(values) {
                        let monthsToSkip = values.months_to_skip;
                        let skipReason = values.skip_reason || '';

                        // Store previous values for history
                        let previousToDate = frm.doc.to_date;
                        let previousDisabled = frm.doc.disabled;

                        // Calculate new dates
                        let currentToDate = new Date(frm.doc.to_date);
                        currentToDate.setDate(1);
                        currentToDate.setMonth(currentToDate.getMonth() + monthsToSkip);

                        let currentDate = new Date();
                        currentDate.setDate(1);
                        currentDate.setMonth(currentDate.getMonth() + monthsToSkip);

                        // Get last day of the target month
                        let lastDayOfToDate = new Date(currentToDate.getFullYear(), currentToDate.getMonth() + 1, 0);
                        let firstDayOfMonth = new Date(currentDate.getFullYear(), currentDate.getMonth(), 1);

                        // Calculate financial impact
                        let monthlyAmount = Math.abs(frm.doc.amount) || 0;
                        let totalSkippedAmount = monthlyAmount * monthsToSkip;

                        // Fetch outstanding balance from Employee Advance
                        let outstandingBalance = 0;

                        // Get Employee Advance details for outstanding balance
                        frappe.call({
                            method: 'frappe.client.get',
                            args: {
                                doctype: 'Employee Advance',
                                filters: {
                                    'employee': frm.doc.employee
                                },
                                fieldname: ['paid_amount', 'return_amount']
                            },
                            async: false,
                            callback: function(response) {
                                if (response.message) {
                                    let paidAmount = response.message.paid_amount || 0;
                                    let returnedAmount = response.message.return_amount || 0;
                                    outstandingBalance = paidAmount - returnedAmount;
                                }
                            }
                        });

                        // Update summary tracking fields
                        frm.set_value('custom_times_skipped', (frm.doc.custom_times_skipped || 0) + 1);
                        frm.set_value('custom_last_skipped_date', frappe.datetime.get_today());
                        frm.set_value('custom_last_skip_months', monthsToSkip);
                        frm.set_value('custom_total_months_skipped', (frm.doc.custom_total_months_skipped || 0) + monthsToSkip);

                        // Add to skip history child table with financial details
                        let skip_log = frm.add_child('custom_skip_history');
                        skip_log.skip_date = frappe.datetime.get_today();
                        skip_log.months_skipped = monthsToSkip;
                        skip_log.restart_date = frappe.datetime.obj_to_str(firstDayOfMonth);
                        skip_log.skipped_by = frappe.session.user;
                        skip_log.previous_to_date = previousToDate;
                        skip_log.new_to_date = frappe.datetime.obj_to_str(lastDayOfToDate);
                        skip_log.reason = skipReason;
                        skip_log.previous_disabled = previousDisabled;

                        // Add financial fields
                        skip_log.monthly_payment_amount = monthlyAmount;
                        skip_log.total_amount_skipped = totalSkippedAmount;
                        skip_log.outstanding_balance = outstandingBalance;

                        frm.refresh_field('custom_skip_history');

                        // Update dates and disable
                        frm.set_value('to_date', frappe.datetime.obj_to_str(lastDayOfToDate));
                        frm.set_value('custom_disable_uncheck_date', frappe.datetime.obj_to_str(firstDayOfMonth));
                        frm.set_value('disabled', 1);

                        frm.save('Update').then(() => {
                            frappe.show_alert({
                                message: __('✓ Skip Payment processed! Deferred: {0}', 
                                    [frappe.format(totalSkippedAmount, {fieldtype: 'Currency'})]),
                                indicator: 'orange'
                            }, 5);

                            frappe.msgprint({
                                title: __('Payment Skipped Successfully'),
                                message: __('Payment has been skipped for <b>{0} months</b>.<br><br>\
                                    <b>Financial Impact:</b><br>\
                                    • Monthly Payment: {1}<br>\
                                    • Amount Deferred: <b>{2}</b><br>\
                                    • Outstanding Balance: {3}<br><br>\
                                    Payment will automatically restart on <b>{4}</b>', 
                                    [
                                        monthsToSkip, 
                                        frappe.format(monthlyAmount, {fieldtype: 'Currency'}),
                                        frappe.format(totalSkippedAmount, {fieldtype: 'Currency'}),
                                        frappe.format(outstandingBalance, {fieldtype: 'Currency'}),
                                        frappe.datetime.str_to_user(frappe.datetime.obj_to_str(firstDayOfMonth))
                                    ]),
                                indicator: 'green'
                            });
                        });

                        dialog.hide();
                    }
                });

                dialog.show();

                // Trigger onchange to show initial info
                dialog.set_value('months_to_skip', 1);
            });
        }

        // One Shot Payment Button - YOUR ORIGINAL WORKING CODE
        if (!frm.is_new()) {
            frm.add_custom_button(__('One Shot Payment'), function() {
                let today = new Date();
                let lastDay = new Date(today.getFullYear(), today.getMonth() + 1, 0);
                let lastDateOfMonth = frappe.datetime.obj_to_str(lastDay);

                frm.set_value('to_date', lastDateOfMonth);
                frm.refresh_field('to_date');

                if (frm.doc.disabled) {
                    frm.set_value('disabled', 0);
                    frm.refresh_field('disabled');
                }

                frappe.call({
                    method: 'frappe.client.get',
                    args: {
                        doctype: 'Employee Advance',
                        filters: {
                            'employee': frm.doc.employee
                        },
                        fieldname: ['paid_amount', 'returned_amount']
                    },
                    callback: function(response) {
                        if (response.message) {
                            let advanceAmount = response.message.paid_amount || 0;
                            let returnedAmount = response.message.return_amount || 0;

                            let finalAmount = advanceAmount - returnedAmount;

                            frm.set_value('amount', finalAmount);
                            frm.refresh_field('amount');
                        }

                        frm.save('Update').then(() => {
                            frappe.msgprint(__('One Shot Payment processed and amount updated.'));
                        });
                    }
                });
            });
        }

        // Show skip count badge/indicator
        if (frm.doc.custom_times_skipped && frm.doc.custom_times_skipped > 0) {
            frm.dashboard.add_indicator(
                __('⚠️ Skipped {0} times ({1} months total)', 
                    [frm.doc.custom_times_skipped, frm.doc.custom_total_months_skipped || 0]), 
                'orange'
            );
        }
    },

    onload: function(frm) {
        // Show skip warning box if has skip history
        if (frm.doc.custom_times_skipped > 0) {
            // Calculate total deferred amount from skip history
            let totalDeferred = 0;
            if (frm.doc.custom_skip_history) {
                frm.doc.custom_skip_history.forEach(function(row) {
                    // totalDeferred += (row.total_amount_skipped || 0);
                });
            }

            let html = `
                <div class="skip-payment-warning" style="padding: 12px; background: #fff3cd; border-left: 4px solid #ffc107; margin: 10px 0; border-radius: 4px;">
                    <div style="display: flex; align-items: center;">
                        <span style="font-size: 24px; margin-right: 12px;">⚠️</span>
                        <div style="flex: 1;">
                            <h5 style="margin: 0 0 8px 0; color: #856404;">Skip Payment History</h5>
                            <div style="color: #856404; font-size: 13px;">
                                <strong>Times Skipped:</strong> ${frm.doc.custom_times_skipped} | 
                                <strong>Total Months:</strong> ${frm.doc.custom_total_months_skipped || 0} | 
                                <strong>Last Skip:</strong> ${frm.doc.custom_last_skipped_date ? frappe.datetime.str_to_user(frm.doc.custom_last_skipped_date) : 'N/A'}
                                ${totalDeferred > 0 ? '<br><strong>Total Deferred Amount:</strong> ' + frappe.format(totalDeferred, {fieldtype: 'Currency'}) : ''}
                            </div>
                        </div>
                    </div>
                </div>
            `;

            // Remove any existing warning before adding new one
            $('.skip-payment-warning').remove();
            // Add warning at the top of the form
            $(frm.fields_dict.employee.wrapper).before(html);
        }
    },

    validate: function(frm) {
        let currentDate = frappe.datetime.get_today();
        let disableUncheckDate = frm.doc.custom_disable_uncheck_date;

        if (disableUncheckDate && currentDate === disableUncheckDate) {
            frm.set_value('disabled', 0);
            frm.refresh_field('disabled');
        }
    }
});

