// === UTILITY FUNCTIONS ===

function parseLocalDate(dateStr) {
    if (!dateStr) return null;
    let parts = String(dateStr).split('-');
    if (parts.length !== 3) return new Date(dateStr);
    return new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]));
}

function checkActiveCurrentMonthSkip(frm) {
    if (!frm.doc.custom_skip_history || frm.doc.custom_skip_history.length === 0) return false;

    let today = new Date();
    let currentYear = today.getFullYear();
    let currentMonth = today.getMonth();

    for (let row of frm.doc.custom_skip_history) {
        let monthsCount = row.months_skipped || 0;
        if (monthsCount === 0) continue;

        let disableStart = null, restartDate = null;

        if (row.disable_start_date && row.restart_date) {
            disableStart = parseLocalDate(row.disable_start_date);
            restartDate = parseLocalDate(row.restart_date);
        } else if (row.restart_date) {
            restartDate = parseLocalDate(row.restart_date);
            disableStart = new Date(restartDate.getFullYear(), restartDate.getMonth() - monthsCount, 1);
        }

        if (disableStart && restartDate) {
            let currentMonthStart = new Date(currentYear, currentMonth, 1);
            let currentMonthEnd = new Date(currentYear, currentMonth + 1, 0);
            if (disableStart <= currentMonthEnd && restartDate > currentMonthStart) return true;
        }
    }
    return false;
}

function showUpcomingSkipSchedule(frm) {
    $('.skip-schedule-banner').remove();
    if (!frm.doc.custom_skip_history || frm.doc.custom_skip_history.length === 0) return;

    let today = frappe.datetime.get_today();
    let upcoming = [];

    frm.doc.custom_skip_history.forEach(row => {
        if (row.disable_start_date && row.disable_start_date >= today) {
            upcoming.push({type: 'disable', date: row.disable_start_date, reason: row.reason});
        }
        if (row.restart_date && row.restart_date >= today) {
            upcoming.push({type: 'enable', date: row.restart_date});
        }
    });

    upcoming.sort((a, b) => new Date(a.date) - new Date(b.date));

    if (upcoming.length > 0) {
        let items = upcoming.slice(0, 4).map(s => {
            let icon = s.type === 'disable' ? '🔴' : '🟢';
            return `${icon} ${frappe.datetime.str_to_user(s.date)}`;
        }).join(' → ');

        let html = `<div class="skip-schedule-banner alert alert-info" style="margin: 10px 0;"><b>Schedule:</b> ${items}</div>`;
        $(frm.fields_dict.employee.wrapper).before(html);
    }
}

function getAlreadySkippedMonths(frm) {
    let skippedMonths = [];
    if (!frm.doc.custom_skip_history || frm.doc.custom_skip_history.length === 0) return skippedMonths;

    frm.doc.custom_skip_history.forEach(row => {
        let monthsCount = row.months_skipped || 0;
        if (monthsCount === 0) return;

        let startDate = null;
        if (row.disable_start_date) {
            startDate = parseLocalDate(row.disable_start_date);
        } else if (row.restart_date) {
            let restartDate = parseLocalDate(row.restart_date);
            startDate = new Date(restartDate.getFullYear(), restartDate.getMonth() - monthsCount, 1);
        }

        if (startDate) {
            for (let i = 0; i < monthsCount; i++) {
                let skipMonth = new Date(startDate.getFullYear(), startDate.getMonth() + i, 1);
                skippedMonths.push({year: skipMonth.getFullYear(), month: skipMonth.getMonth()});
            }
        }
    });
    return skippedMonths;
}

function groupConsecutiveMonths(months) {
    if (months.length === 0) return [];

    let sorted = [...months].sort((a, b) => a.year !== b.year ? a.year - b.year : a.month - b.month);
    let groups = [];
    let currentGroup = [sorted[0]];

    for (let i = 1; i < sorted.length; i++) {
        let prev = sorted[i - 1], curr = sorted[i];
        let prevDate = new Date(prev.year, prev.month + 1, 1);

        if (prevDate.getFullYear() === curr.year && prevDate.getMonth() === curr.month) {
            currentGroup.push(curr);
        } else {
            groups.push(currentGroup);
            currentGroup = [curr];
        }
    }
    groups.push(currentGroup);
    return groups;
}

// === PAYROLL CHECK FUNCTIONS ===

async function fetchPayrollProcessedMonths(employee, startYear, endYear) {
    let processedMonths = [];
    try {
        let result = await frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Salary Slip',
                filters: {
                    employee: employee,
                    start_date: ['>=', `${startYear}-01-01`],
                    end_date: ['<=', `${endYear}-12-31`],
                    docstatus: ['!=', 2]
                },
                fields: ['name', 'start_date', 'docstatus'],
                limit_page_length: 0
            }
        });

        if (result && result.message) {
            result.message.forEach(slip => {
                let slipDate = parseLocalDate(slip.start_date);
                if (slipDate) {
                    processedMonths.push({
                        year: slipDate.getFullYear(),
                        month: slipDate.getMonth(),
                        docstatus: slip.docstatus,
                        name: slip.name
                    });
                }
            });
        }
    } catch (e) {
        console.error('Error fetching payroll:', e);
    }
    return processedMonths;
}

function getMonthsFromSkipRow(skipRow) {
    let months = [];
    let monthsCount = skipRow.months_skipped || 0;
    if (monthsCount === 0) return months;

    let startDate = null;
    if (skipRow.disable_start_date) {
        startDate = parseLocalDate(skipRow.disable_start_date);
    } else if (skipRow.restart_date) {
        let restartDate = parseLocalDate(skipRow.restart_date);
        startDate = new Date(restartDate.getFullYear(), restartDate.getMonth() - monthsCount, 1);
    }

    if (startDate) {
        for (let i = 0; i < monthsCount; i++) {
            let skipMonth = new Date(startDate.getFullYear(), startDate.getMonth() + i, 1);
            months.push({
                year: skipMonth.getFullYear(),
                month: skipMonth.getMonth()
            });
        }
    }
    return months;
}

async function checkPayrollForMonths(employee, months) {
    if (!months || months.length === 0) return { hasPayroll: false, details: [] };

    let minYear = Math.min(...months.map(m => m.year));
    let maxYear = Math.max(...months.map(m => m.year));

    let payrollMonths = await fetchPayrollProcessedMonths(employee, minYear, maxYear);

    let conflictingMonths = [];
    let monthNames = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];

    months.forEach(m => {
        let found = payrollMonths.find(p => p.year === m.year && p.month === m.month);
        if (found) {
            conflictingMonths.push({
                year: m.year,
                month: m.month,
                monthName: monthNames[m.month],
                salarySlip: found.name,
                docstatus: found.docstatus
            });
        }
    });

    return {
        hasPayroll: conflictingMonths.length > 0,
        details: conflictingMonths
    };
}

// === FETCH ACTUAL DEDUCTIONS FROM SUBMITTED SALARY SLIPS (FIXED - NO CHILD TABLE DIRECT QUERY) ===

async function fetchActualDeductions(employee, additionalSalaryName, salaryComponent, fromDate, toDate) {
    let result = {
        totalDeducted: 0,
        slipCount: 0,
        slips: [],
        error: null
    };

    try {
        // Step 1: Get all SUBMITTED salary slips for this employee in the date range
        let slipResult = await frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Salary Slip',
                filters: {
                    employee: employee,
                    start_date: ['>=', fromDate],
                    end_date: ['<=', toDate],
                    docstatus: 1  // Only Submitted
                },
                fields: ['name', 'start_date', 'end_date'],
                limit_page_length: 0,
                order_by: 'start_date asc'
            }
        });

        if (!slipResult || !slipResult.message || slipResult.message.length === 0) {
            return result; // No submitted slips found — 0 deducted
        }

        // Step 2: Fetch each salary slip's full document to read deductions child table
        for (let slip of slipResult.message) {
            try {
                let slipDoc = await frappe.call({
                    method: 'frappe.client.get',
                    args: {
                        doctype: 'Salary Slip',
                        name: slip.name
                    }
                });

                if (slipDoc && slipDoc.message && slipDoc.message.deductions) {
                    let deductions = slipDoc.message.deductions;

                    for (let deduction of deductions) {
                        // STRICT MATCH: salary_component AND additional_salary must both match
                        if (deduction.salary_component === salaryComponent &&
                            deduction.additional_salary === additionalSalaryName) {

                            let amount = Math.abs(parseFloat(deduction.amount) || 0);
                            result.totalDeducted += amount;
                            result.slipCount++;
                            result.slips.push({
                                slipName: slip.name,
                                amount: amount,
                                startDate: slip.start_date,
                                additionalSalary: deduction.additional_salary || ''
                            });
                        }
                    }
                }
            } catch (slipErr) {
                console.warn('Could not fetch salary slip:', slip.name, slipErr);
                // Continue with other slips — don't block entire operation
            }
        }

    } catch (e) {
        console.error('Error fetching actual deductions:', e);
        result.error = e.message || JSON.stringify(e) || String(e);
    }

    return result;
}

