    let toDate = parseLocalDate(frm.doc.to_date);
    let toYear = toDate.getFullYear();

    let fromDate = parseLocalDate(frm.doc.from_date);
    let startYear = fromDate.getFullYear();
    let endYear = toYear;

    let monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
    let fullMonthNames = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];

    let alreadySkippedMonths = getAlreadySkippedMonths(frm);
    let payrollProcessedMonths = await fetchPayrollProcessedMonths(frm.doc.employee, startYear, endYear);

    function isMonthSkipped(year, month) {
        return alreadySkippedMonths.some(m => m.year === year && m.month === month);
    }

    function isPayrollDone(year, month) {
        return payrollProcessedMonths.some(m => m.year === year && m.month === month);
    }

    function getPayrollStatus(year, month) {
        let found = payrollProcessedMonths.find(m => m.year === year && m.month === month);
        return found ? (found.docstatus === 1 ? 'Submitted' : 'Draft') : null;
    }

    function buildMonthGrid(year) {
        let html = `
            <div class="text-center mb-3">
                <button type="button" class="btn btn-xs btn-default year-nav" data-dir="prev" ${year <= startYear ? 'disabled' : ''}>◄</button>
                <span class="h4 mx-3">${year}</span>
                <button type="button" class="btn btn-xs btn-default year-nav" data-dir="next" ${year >= endYear ? 'disabled' : ''}>►</button>
            </div>
            <div class="month-grid">
        `;

        for (let i = 0; i < 12; i++) {
            let monthDate = new Date(year, i, 1);
            let currentDateFirst = new Date(currentYear, currentMonth, 1);
            let fromDateFirst = new Date(fromDate.getFullYear(), fromDate.getMonth(), 1);
            let toDateFirst = new Date(toDate.getFullYear(), toDate.getMonth(), 1);

            let isBeforeFromDate = monthDate < fromDateFirst;
            let isAfterToDate = monthDate > toDateFirst;
            let isBeforeCurrentMonth = monthDate < currentDateFirst;
            let isAlreadySkipped = isMonthSkipped(year, i);
            let hasPayroll = isPayrollDone(year, i);
            let isCurrent = (year === currentYear && i === currentMonth);

            let isDisabled = isBeforeFromDate || isAfterToDate || isBeforeCurrentMonth || isAlreadySkipped || hasPayroll;

            let cls = 'month-box';
            let label = '';

            // if (isBeforeFromDate) {
            //     cls += ' disabled';
            //     label = 'Before Start';
            // } else if (hasPayroll) {
            //     cls += ' payroll';
            //     label = getPayrollStatus(year, i) === 'Submitted' ? 'Payroll ✓' : 'Draft';
            // } else if (isAlreadySkipped) {
            //     cls += ' skipped';
            //     label = 'Skipped';
            // } else if (isBeforeCurrentMonth) {
            //     // cls += ' disabled';
            //     cls += ' current selectable';
            //     label = 'Past';
            // } else if (isAfterToDate) {
            //     cls += ' disabled';
            //     label = 'Beyond';
            // } else if (isCurrent) {
            //     cls += ' current selectable';
            //     label = 'Current';
            // } else {
            //     cls += ' selectable';
            // }
            if (isBeforeFromDate) {
                cls += ' disabled';
                label = 'Before Start';
            } else if (isAfterToDate) {
                cls += ' disabled';
                label = 'Beyond';
            } else if (hasPayroll) {
                cls += ' payroll';
                label = getPayrollStatus(year, i) === 'Submitted' ? 'Payroll ✓' : 'Draft';
