            selectedMonths.sort((a, b) => a.year !== b.year ? a.year - b.year : a.month - b.month);

            let tags = selectedMonths.map(m => `<span class="badge" style="background:#5e64ff;color:#fff;margin:2px;">${m.name} ${m.year}</span>`).join(' ');
            $wrapper.find('#skip-summary').html(`<b>Selected (${count}):</b> ${tags}`);

            let groups = groupConsecutiveMonths(selectedMonths);
            let groupsHtml = groups.map((g, i) => {
                let label = g.map(m => m.name + ' ' + m.year).join(', ');
                let first = g[0], last = g[g.length - 1];
                let disableDate = new Date(first.year, first.month, 1);
                let restartDate = new Date(last.year, last.month + 1, 1);
                let isImmediate = disableDate <= new Date();
                return `<div style="margin:4px 0;"><b>Row ${i + 1}:</b> ${label}<br>
                    <small>${isImmediate ? '⚡ Immediate' : '📅 ' + frappe.datetime.str_to_user(frappe.datetime.obj_to_str(disableDate))} → ${frappe.datetime.str_to_user(frappe.datetime.obj_to_str(restartDate))}</small></div>`;
            }).join('');
            $wrapper.find('#skip-groups').html(`<div class="skip-groups"><b>Schedule (${groups.length} row${groups.length > 1 ? 's' : ''}):</b>${groupsHtml}</div>`);

            let monthlyAmt = Math.abs(frm.doc.amount) || 0;
            let totalDeferred = monthlyAmt * count;
            let currentToDate = parseLocalDate(frm.doc.to_date);
            let newToDate = new Date(currentToDate.getFullYear(), currentToDate.getMonth() + count + 1, 0);

            $wrapper.find('#skip-impact').html(`
                <div class="skip-impact">
                    <b>Impact:</b> ${frappe.format(totalDeferred, {fieldtype: 'Currency'})} deferred | 
                    New To Date: ${frappe.datetime.str_to_user(frappe.datetime.obj_to_str(newToDate))}
                </div>
            `);
        }

        function attachHandlers() {
            $wrapper.find('.month-box.selectable').off('click').on('click', function() {
                let $this = $(this);
                let month = parseInt($this.data('month'));
                let year = parseInt($this.data('year'));
                let name = $this.data('name');
                let isCurrent = parseInt($this.data('current')) === 1;

                let idx = selectedMonths.findIndex(m => m.month === month && m.year === year);

                if (idx >= 0) {
                    selectedMonths.splice(idx, 1);
                    $this.removeClass('selected');
                } else {
                    selectedMonths.push({month, year, name, isCurrent});
                    $this.addClass('selected');
                }
                updateSummary();
            });
        }

        $wrapper.off('click', '.year-nav').on('click', '.year-nav', function(e) {
            e.preventDefault();
            let dir = $(this).data('dir');
            if (dir === 'prev' && displayYear > startYear) updateGrid(displayYear - 1);
            else if (dir === 'next' && displayYear < endYear) updateGrid(displayYear + 1);
        });

        attachHandlers();
    }

    setTimeout(initHandlers, 150);
}

// === EXECUTE SKIP PAYMENT ===

function executeSkipPayment(frm, selectedMonths, skipReason) {
    selectedMonths.sort((a, b) => a.year !== b.year ? a.year - b.year : a.month - b.month);

    let totalMonths = selectedMonths.length;
    let previousToDate = frm.doc.to_date;
    let previousDisabled = frm.doc.disabled;
    let groups = groupConsecutiveMonths(selectedMonths);

    let currentToDate = parseLocalDate(frm.doc.to_date);
    let newToDate = new Date(currentToDate.getFullYear(), currentToDate.getMonth() + totalMonths + 1, 0);

    let monthlyAmount = Math.abs(frm.doc.amount) || 0;
    let today = new Date();
    today.setHours(0, 0, 0, 0);
    let todayStr = frappe.datetime.get_today();

    let shouldDisableNow = false;
    let earliestRestartDate = null;
    let earliestDisableDate = null;

    groups.forEach(group => {
        let groupMonthsStr = group.map(m => m.name + ' ' + m.year).join(', ');
        let first = group[0], last = group[group.length - 1];

        let disableStartDate = new Date(first.year, first.month, 1);
        let restartDate = new Date(last.year, last.month + 1, 1);

        let disableStartDateStr = frappe.datetime.obj_to_str(disableStartDate);
        let restartDateStr = frappe.datetime.obj_to_str(restartDate);

        if (disableStartDate <= today) {
            shouldDisableNow = true;
            if (!earliestRestartDate || restartDate < parseLocalDate(earliestRestartDate)) {
                earliestRestartDate = restartDateStr;
            }
        }

        if (!earliestDisableDate || disableStartDate < parseLocalDate(earliestDisableDate)) {
            earliestDisableDate = disableStartDateStr;
        }

        let skip_log = frm.add_child('custom_skip_history');
        skip_log.skip_date = todayStr;
        skip_log.months_skipped = group.length;
        skip_log.restart_date = restartDateStr;
        skip_log.disable_start_date = disableStartDateStr;
        skip_log.skipped_by = frappe.session.user;
        skip_log.previous_to_date = previousToDate;
        skip_log.new_to_date = frappe.datetime.obj_to_str(newToDate);
        skip_log.reason = skipReason ? skipReason + ' | ' + groupMonthsStr : groupMonthsStr;
        skip_log.previous_disabled = previousDisabled ? 1 : 0;
        skip_log.is_processed = 0;

        try {
            skip_log.monthly_payment_amount = monthlyAmount;
            skip_log.total_amount_skipped = monthlyAmount * group.length;
        } catch(e) {}
    });

    frm.refresh_field('custom_skip_history');
    frm.set_value('custom_times_skipped', (frm.doc.custom_times_skipped || 0) + groups.length);
    frm.set_value('custom_last_skipped_date', todayStr);
    frm.set_value('custom_last_skip_months', totalMonths);
    frm.set_value('custom_total_months_skipped', (frm.doc.custom_total_months_skipped || 0) + totalMonths);
    frm.set_value('to_date', frappe.datetime.obj_to_str(newToDate));

    if (shouldDisableNow) {
        frm.set_value('disabled', 1);
        frm.set_value('custom_disable_uncheck_date', earliestRestartDate);
    } else {
        frm.set_value('custom_next_disable_date', earliestDisableDate);
    }

    frm.save('Update').then(() => {
        frappe.show_alert({message: __('Skip applied: {0} month(s)', [totalMonths]), indicator: 'green'}, 4);
        frappe.msgprint({
            title: __('Payment Skipped'),
            message: `<p><b>Months:</b> ${totalMonths} | <b>Rows:</b> ${groups.length}</p>
                <p><b>Deferred:</b> ${frappe.format(monthlyAmount * totalMonths, {fieldtype: 'Currency'})}</p>
                <p><b>New To Date:</b> ${frappe.datetime.str_to_user(frappe.datetime.obj_to_str(newToDate))}</p>
                ${shouldDisableNow ? '<p>⚡ Document disabled immediately</p>' : '<p>📅 Will disable on scheduled date</p>'}`,
            indicator: 'green'
        });
    }).catch(err => {
        frappe.msgprint({title: __('Error'), message: err.message || err, indicator: 'red'});
        frm.reload_doc();
    });
}

// === REVERT LAST SKIP (WITH PAYROLL CHECK) ===

async function revertLastSkip(frm) {
    let skipHistory = frm.doc.custom_skip_history;
    let lastSkip = skipHistory[skipHistory.length - 1];
    let lastSkipIndex = skipHistory.length - 1;

    if (!lastSkip) {
        frappe.msgprint(__('No skip history found.'));
        return;
    }

    frappe.show_alert({message: __('Checking payroll status...'), indicator: 'blue'}, 2);

    let skippedMonths = getMonthsFromSkipRow(lastSkip);
    let payrollCheck = await checkPayrollForMonths(frm.doc.employee, skippedMonths);

    if (payrollCheck.hasPayroll) {
        let monthsList = payrollCheck.details.map(d => {
            let status = d.docstatus === 1 ? 'Submitted' : 'Draft';
            return `<li><b>${d.monthName} ${d.year}</b> - ${d.salarySlip} (${status})</li>`;
        }).join('');

        frappe.msgprint({
            title: __('Cannot Revert Skip'),
            message: `
                <p>Cannot revert because <b>payroll exists</b> for:</p>
                <ul>${monthsList}</ul>
                <p><b>Solution:</b> Cancel the Salary Slip(s) first.</p>
            `,
            indicator: 'red'
        });
        return;
    }

    let currentToDate = parseLocalDate(frm.doc.to_date);
    let monthsToSubtract = lastSkip.months_skipped || 0;
    let calculatedRestoreDate = null;

    if (monthsToSubtract > 0 && currentToDate) {
        calculatedRestoreDate = new Date(currentToDate.getFullYear(), currentToDate.getMonth() - monthsToSubtract + 1, 0);
    }

    let restoreDisplay = calculatedRestoreDate ? 
        frappe.datetime.str_to_user(frappe.datetime.obj_to_str(calculatedRestoreDate)) : 
        (lastSkip.previous_to_date ? frappe.datetime.str_to_user(lastSkip.previous_to_date) : 'N/A');

    let monthNames = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];
    let skippedMonthsDisplay = skippedMonths.map(m => `${monthNames[m.month]} ${m.year}`).join(', ');

    frappe.confirm(
        `<p><b>Revert last skip?</b></p>
         <p><b>Months:</b> ${skippedMonthsDisplay}</p>
         <p><b>Reason:</b> ${lastSkip.reason || 'N/A'}</p>
         <hr>
         <p><b>Restore To Date:</b> ${restoreDisplay}</p>
         <p style="color: green;">✓ No payroll found - safe to revert</p>`,
        () => {
            if (calculatedRestoreDate) {
                frm.set_value('to_date', frappe.datetime.obj_to_str(calculatedRestoreDate));
            } else if (lastSkip.previous_to_date) {
                frm.set_value('to_date', lastSkip.previous_to_date);
            }

            let remainingSkips = skipHistory.slice(0, lastSkipIndex);
            let shouldBeDisabled = false;
            let today = new Date();
            today.setHours(0, 0, 0, 0);

            remainingSkips.forEach(skip => {
                let disableStart = null, restartDate = null;
                let skipMonths = skip.months_skipped || 0;

                if (skip.disable_start_date && skip.restart_date) {
                    disableStart = parseLocalDate(skip.disable_start_date);
                    restartDate = parseLocalDate(skip.restart_date);
                } else if (skip.restart_date && skipMonths > 0) {
                    restartDate = parseLocalDate(skip.restart_date);
                    disableStart = new Date(restartDate.getFullYear(), restartDate.getMonth() - skipMonths, 1);
                }

                if (disableStart && restartDate && disableStart <= today && today < restartDate) {
                    shouldBeDisabled = true;
                }
            });

            if (!shouldBeDisabled) {
                frm.set_value('disabled', lastSkip.previous_disabled ? 1 : 0);
            }

            frm.set_value('custom_times_skipped', Math.max(0, (frm.doc.custom_times_skipped || 1) - 1));
            frm.set_value('custom_total_months_skipped', Math.max(0, (frm.doc.custom_total_months_skipped || 0) - (lastSkip.months_skipped || 0)));
            frm.set_value('custom_disable_uncheck_date', '');
            frm.set_value('custom_next_disable_date', '');

            if (skipHistory.length > 1) {
                let prev = skipHistory[skipHistory.length - 2];
                frm.set_value('custom_last_skipped_date', prev.skip_date);
                frm.set_value('custom_last_skip_months', prev.months_skipped);
            } else {
                frm.set_value('custom_last_skipped_date', '');
                frm.set_value('custom_last_skip_months', 0);
            }

            frm.doc.custom_skip_history.splice(lastSkipIndex, 1);
            frm.refresh_field('custom_skip_history');

            frm.save('Update').then(() => {
                frappe.show_alert({message: __('Skip reverted'), indicator: 'green'}, 3);
            }).catch(err => {
                frappe.msgprint({title: __('Error'), message: err.message || err, indicator: 'red'});
                frm.reload_doc();
            });
        }
    );
}

// === ONE SHOT PAYMENT (CALCULATES FROM ACTUAL SALARY SLIP DEDUCTIONS) ===

async function processOneShotPayment(frm) {
    if (frm.doc.custom_one_shot_payment_date) {
        frappe.msgprint({title: __('Already Applied'), message: __('One Shot is already applied. Use Revert One Shot first.'), indicator: 'orange'});
        return;
    }

    // EDGE CASE: Block if document is disabled (active skip in progress)
    if (frm.doc.disabled) {
        let hasActiveSkip = checkActiveCurrentMonthSkip(frm);
        if (hasActiveSkip) {
            frappe.msgprint({
                title: __('Document is Disabled'),
                message: __('This Additional Salary is currently disabled due to an active skip. You must either:<br><br>' +
                    '1. <b>Revert the skip</b> first, then apply One Shot, or<br>' +
                    '2. <b>Wait until the skip period ends</b> and the document re-enables automatically.'),
                indicator: 'orange'
            });
            return;
        }
    }

    // EDGE CASE: Block if document has unsaved changes
    if (frm.dirty()) {
        frappe.msgprint({
            title: __('Unsaved Changes'),
            message: __('Please save the document first before applying One Shot Payment.'),
            indicator: 'orange'
        });
        return;
    }

    // Check if this Additional Salary is linked to an Employee Advance
    let refDoctype = frm.doc.ref_doctype;
    let refDocname = frm.doc.ref_docname;

    if (refDoctype !== 'Employee Advance' || !refDocname) {
        frappe.msgprint({
            title: __('No Employee Advance Linked'),
            message: __('One Shot Payment requires a linked Employee Advance.<br><br>' +
                'This Additional Salary has ref_doctype = "<b>{0}</b>" and ref_docname = "<b>{1}</b>".',
                [refDoctype || 'empty', refDocname || 'empty']),
            indicator: 'red'
        });
        return;
    }

    // EDGE CASE: Block if from_date or to_date is missing
    if (!frm.doc.from_date || !frm.doc.to_date) {
        frappe.msgprint({
            title: __('Missing Dates'),
            message: __('From Date and To Date must be set before applying One Shot Payment.'),
            indicator: 'red'
        });
        return;
    }

    // EDGE CASE: Block if amount is 0 or not set
    if (!frm.doc.amount || frm.doc.amount === 0) {
        frappe.msgprint({
            title: __('No Amount'),
            message: __('Additional Salary amount is zero or not set. Cannot apply One Shot.'),
            indicator: 'red'
        });
        return;
    }

    frappe.show_alert({message: __('Calculating remaining amount from salary slips...'), indicator: 'blue'}, 3);

    let today = new Date();
    let lastDay = new Date(today.getFullYear(), today.getMonth() + 1, 0);
    let lastDateOfMonth = frappe.datetime.obj_to_str(lastDay);

    let originalToDate = frm.doc.to_date;
    let originalAmount = frm.doc.amount;
    let hasActiveSkip = checkActiveCurrentMonthSkip(frm);

    try {
        // === PAYROLL CHECK: Block if salary slip already exists for current month ===
        let currentMonthCheck = [{year: today.getFullYear(), month: today.getMonth()}];
        let payrollCheck = await checkPayrollForMonths(frm.doc.employee, currentMonthCheck);

        if (payrollCheck.hasPayroll) {
            let monthNames = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];
            let detail = payrollCheck.details[0];
            let status = detail.docstatus === 1 ? 'Submitted' : 'Draft';

            frappe.msgprint({
                title: __('Cannot Apply One Shot'),
                message: `<p>Payroll already exists for <b>${monthNames[today.getMonth()]} ${today.getFullYear()}</b>.</p>
                    <p><b>Salary Slip:</b> <a href="/app/salary-slip/${detail.salarySlip}" target="_blank">${detail.salarySlip}</a> (${status})</p>
                    <p><b>Solution:</b> ${status === 'Submitted' ? 'Cancel the Salary Slip first, then apply One Shot.' : 'Delete the Draft Salary Slip first, then apply One Shot.'}</p>`,
                indicator: 'red'
            });
            return;
        }

        // === FETCH EMPLOYEE ADVANCE DATA ===
        let advanceDoc = await frappe.call({
            method: 'frappe.client.get_value',
            args: {
                doctype: 'Employee Advance',
                filters: { name: refDocname },
                fieldname: ['custom_remaining__amount', 'advance_amount', 'paid_amount', 'return_amount', 'name', 'status', 'docstatus']
            }
        });

        let advanceData = advanceDoc && advanceDoc.message;

        // EDGE CASE: Employee Advance not found
        if (!advanceData || !advanceData.name) {
            frappe.msgprint({
                title: __('Employee Advance Not Found'),
                message: __('Could not fetch Employee Advance: <b>{0}</b>.', [refDocname]),
                indicator: 'red'
            });
            return;
        }

        // EDGE CASE: Employee Advance is cancelled
        if (advanceData.docstatus === 2) {
            frappe.msgprint({
                title: __('Employee Advance Cancelled'),
                message: __('Employee Advance <b>{0}</b> has been cancelled.', [refDocname]),
                indicator: 'red'
            });
            return;
        }

        // EDGE CASE: Employee Advance is in draft
        if (advanceData.docstatus === 0) {
            frappe.msgprint({
                title: __('Employee Advance Not Submitted'),
                message: __('Employee Advance <b>{0}</b> is still in Draft.', [refDocname]),
                indicator: 'orange'
            });
            return;
        }

        let paidAmount = parseFloat(advanceData.paid_amount) || 0;
        let advanceAmount = parseFloat(advanceData.advance_amount) || 0;
        let returnAmount = parseFloat(advanceData.return_amount) || 0;
        let customRemainingAmount = parseFloat(advanceData.custom_remaining__amount) || 0;
        let monthlyAmount = Math.abs(frm.doc.amount) || 0;

        // EDGE CASE: paid_amount is 0
        if (paidAmount <= 0) {
            frappe.msgprint({
                title: __('No Paid Amount'),
                message: __('Employee Advance <b>{0}</b> has paid_amount = 0. Nothing to recover.', [refDocname]),
                indicator: 'orange'
            });
            return;
        }

        // === FETCH ACTUAL DEDUCTIONS FROM SUBMITTED SALARY SLIPS ===
        let deductionData = await fetchActualDeductions(
            frm.doc.employee,
            frm.doc.name,
            frm.doc.salary_component,
            frm.doc.from_date,
            frm.doc.to_date
        );

        if (deductionData.error) {
            frappe.msgprint({
                title: __('Error Fetching Deductions'),
                message: __('Could not fetch salary slip deductions: {0}<br><br>Please try again.', [deductionData.error]),
                indicator: 'red'
            });
            return;
        }

        let totalAlreadyDeducted = deductionData.totalDeducted;
        let submittedSlipCount = deductionData.slipCount;

        // === CALCULATE REMAINING: paid_amount - total_already_deducted ===
        let calculatedRemaining = paidAmount - totalAlreadyDeducted;

        // EDGE CASE: Calculated remaining is 0 or negative
        if (calculatedRemaining <= 0) {
            frappe.msgprint({
                title: __('Fully Recovered'),
                message: `<p>The entire amount has already been deducted through payroll.</p>
                    <table style="width:100%; margin: 10px 0;">
                        <tr><td>Paid Amount:</td><td><b>${frappe.format(paidAmount, {fieldtype: 'Currency'})}</b></td></tr>
                        <tr><td>Total Deducted (${submittedSlipCount} slips):</td><td><b>${frappe.format(totalAlreadyDeducted, {fieldtype: 'Currency'})}</b></td></tr>
                        <tr style="border-top: 2px solid #333;"><td><b>Remaining:</b></td><td><b style="color: green;">${frappe.format(calculatedRemaining, {fieldtype: 'Currency'})}</b></td></tr>
                    </table>
                    <p>No One Shot needed — the advance is already fully recovered.</p>`,
                indicator: 'green'
            });
            return;
        }

        // === CROSS-CHECK: Compare calculated vs custom_remaining_amount ===
        let mismatchWarning = '';
        let hasMismatch = false;

        if (customRemainingAmount !== undefined && customRemainingAmount !== null) {
            let difference = Math.abs(calculatedRemaining - customRemainingAmount);

            if (difference > 0.01) {
                hasMismatch = true;
                mismatchWarning = `
                    <div style="margin: 10px 0; padding: 10px; background: #fff3cd; border-left: 4px solid #ffc107; border-radius: 4px;">
                        <b>⚠️ Amount Mismatch Detected:</b><br>
                        <table style="width:100%; margin-top: 5px;">
                            <tr>
                                <td>Calculated (paid_amount − deductions):</td>
                                <td><b>${frappe.format(calculatedRemaining, {fieldtype: 'Currency'})}</b></td>
                            </tr>
                            <tr>
                                <td>Employee Advance custom_remaining_amount:</td>
                                <td><b>${frappe.format(customRemainingAmount, {fieldtype: 'Currency'})}</b></td>
                            </tr>
                            <tr>
                                <td>Difference:</td>
                                <td><b style="color: #c62828;">${frappe.format(difference, {fieldtype: 'Currency'})}</b></td>
                            </tr>
                        </table>
                        <p style="margin-top: 8px; font-size: 12px;">
                            The <b>calculated amount</b> (from actual submitted salary slips) will be used. 
                            Please verify <code>custom_remaining_amount</code> on the Employee Advance if this seems incorrect.
                        </p>
                    </div>`;
            }
        }

        // Build deduction detail rows for the confirmation dialog
        let deductionDetailHtml = '';
        if (deductionData.slips.length > 0) {
            let slipRows = deductionData.slips.map(s => {
                return `<tr>
                    <td><a href="/app/salary-slip/${s.slipName}" target="_blank">${s.slipName}</a></td>
                    <td>${s.startDate ? frappe.datetime.str_to_user(s.startDate) : '-'}</td>
                    <td style="text-align:right;">${frappe.format(s.amount, {fieldtype: 'Currency'})}</td>
                </tr>`;
            }).join('');

            deductionDetailHtml = `
                <details style="margin: 10px 0;">
                    <summary style="cursor: pointer; color: #5e64ff;"><b>View ${submittedSlipCount} Salary Slip Deduction(s)</b></summary>
                    <table style="width:100%; margin-top: 5px; font-size: 12px;" border="1" cellpadding="5" cellspacing="0">
                        <thead style="background: #f5f7fa;">
                            <tr><th>Salary Slip</th><th>Period</th><th style="text-align:right;">Amount</th></tr>
                        </thead>
                        <tbody>${slipRows}</tbody>
                        <tfoot style="background: #f5f7fa; font-weight: bold;">
                            <tr><td colspan="2">Total Deducted</td><td style="text-align:right;">${frappe.format(totalAlreadyDeducted, {fieldtype: 'Currency'})}</td></tr>
                        </tfoot>
                    </table>
                </details>`;
        } else {
            deductionDetailHtml = `<p style="color: #856404;"><i>No submitted salary slips found with deductions for this component — full amount will be used.</i></p>`;
        }

        // === EDGE CASE WARNINGS ===
        let partialWarning = '';
        if (calculatedRemaining < monthlyAmount) {
            partialWarning = `<p style="color:#856404;">⚠️ Remaining (${frappe.format(calculatedRemaining, {fieldtype: 'Currency'})}) is less than monthly deduction (${frappe.format(monthlyAmount, {fieldtype: 'Currency'})}). This is a partial settlement.</p>`;
        }

        let sanityWarning = '';
        if (monthlyAmount > 0 && calculatedRemaining > monthlyAmount * 120) {
            sanityWarning = `<p style="color:#c62828;">⚠️ <b>Warning:</b> Remaining amount is more than 10 years of monthly deductions. Please verify.</p>`;
        }

        let skipWarning = hasActiveSkip ? '<p style="color:#c62828;">⚡ Active skip will be overridden - document will be re-enabled</p>' : '';

        // === EDGE CASE: remaining equals monthly (only 1 month left) ===
        if (calculatedRemaining === monthlyAmount) {
            frappe.confirm(
                `<p><b>Note:</b> The remaining amount (${frappe.format(calculatedRemaining, {fieldtype: 'Currency'})}) ` +
                `equals the monthly deduction amount.</p>` +
                `<p>This means only <b>1 month of deduction remains</b>. One Shot will have the same effect as normal payroll.</p>` +
                `${mismatchWarning}` +
                `${deductionDetailHtml}` +
                `<p>Do you still want to proceed?</p>`,
                () => { 
                    showOneShotFinalConfirmation(frm, calculatedRemaining, monthlyAmount, originalToDate, originalAmount, lastDateOfMonth, hasActiveSkip, refDocname, paidAmount, totalAlreadyDeducted, submittedSlipCount, mismatchWarning, customRemainingAmount, hasMismatch);
                },
                () => {}
            );
            return;
        }

        // === MAIN CONFIRMATION DIALOG ===
        frappe.confirm(
            `<p><b>One Shot Payment — Calculation Breakdown:</b></p>
             <table style="width:100%; margin: 10px 0; border-collapse: collapse;">
                <tr><td style="padding:4px;">Employee Advance:</td><td style="padding:4px;"><b><a href="/app/employee-advance/${refDocname}" target="_blank">${refDocname}</a></b></td></tr>
                <tr><td style="padding:4px;">Paid Amount (base):</td><td style="padding:4px;"><b>${frappe.format(paidAmount, {fieldtype: 'Currency'})}</b></td></tr>
                <tr><td style="padding:4px;">Total Deducted (${submittedSlipCount} submitted slips):</td><td style="padding:4px;"><b style="color: green;">− ${frappe.format(totalAlreadyDeducted, {fieldtype: 'Currency'})}</b></td></tr>
                <tr style="border-top: 2px solid #333;"><td style="padding:4px;"><b>Calculated Remaining:</b></td><td style="padding:4px;"><b style="color: #c62828; font-size: 1.2em;">${frappe.format(calculatedRemaining, {fieldtype: 'Currency'})}</b></td></tr>
                <tr><td style="padding:4px; color:#888;">Current Monthly Amount:</td><td style="padding:4px; color:#888;">${frappe.format(monthlyAmount, {fieldtype: 'Currency'})}</td></tr>
             </table>
             ${mismatchWarning}
             ${deductionDetailHtml}
             <hr>
             <p><b>What will happen:</b></p>
             <p>• Amount will change: ${frappe.format(monthlyAmount, {fieldtype: 'Currency'})} → <b>${frappe.format(calculatedRemaining, {fieldtype: 'Currency'})}</b></p>
             <p>• To Date will change to: <b>${frappe.datetime.str_to_user(lastDateOfMonth)}</b> (end of current month)</p>
             <p>• This full remaining amount will be deducted in the next payroll run</p>
             ${partialWarning}
             ${sanityWarning}
             ${skipWarning}`,
            () => {
                applyOneShotPayment(frm, calculatedRemaining, originalToDate, originalAmount, lastDateOfMonth);
            },
            () => {}
        );

    } catch(err) {
        console.error('One Shot Payment error:', err);
        frappe.msgprint({
            title: __('Error'),
            message: __('Failed to process One Shot Payment.<br><br><b>Error:</b> {0}', [err.message || JSON.stringify(err) || String(err)]),
            indicator: 'red'
        });
    }
}

// Helper: Final confirmation for edge case (remaining = monthly)
function showOneShotFinalConfirmation(frm, calculatedRemaining, monthlyAmount, originalToDate, originalAmount, lastDateOfMonth, hasActiveSkip, refDocname, paidAmount, totalAlreadyDeducted, submittedSlipCount, mismatchWarning, customRemainingAmount, hasMismatch) {
    let skipWarning = hasActiveSkip ? '<p style="color:#c62828;">⚡ Active skip will be overridden</p>' : '';

    frappe.confirm(
        `<p><b>Confirm One Shot Payment:</b></p>
         <table style="width:100%; margin: 10px 0;">
            <tr><td>Employee Advance:</td><td><b>${refDocname}</b></td></tr>
            <tr><td>Paid Amount:</td><td><b>${frappe.format(paidAmount, {fieldtype: 'Currency'})}</b></td></tr>
            <tr><td>Already Deducted (${submittedSlipCount} slips):</td><td><b>${frappe.format(totalAlreadyDeducted, {fieldtype: 'Currency'})}</b></td></tr>
            <tr><td>Amount to deduct now:</td><td><b style="color: #c62828;">${frappe.format(calculatedRemaining, {fieldtype: 'Currency'})}</b></td></tr>
            <tr><td>To Date:</td><td><b>${frappe.datetime.str_to_user(lastDateOfMonth)}</b></td></tr>
         </table>
         ${mismatchWarning}
         ${skipWarning}`,
        () => {
            applyOneShotPayment(frm, calculatedRemaining, originalToDate, originalAmount, lastDateOfMonth);
        },
        () => {}
    );
}

// Helper: Actually apply the one shot payment values and save
function applyOneShotPayment(frm, remainingAmount, originalToDate, originalAmount, lastDateOfMonth) {
    // Store original values for revert
    frm.set_value('custom_one_shot_original_to_date', originalToDate);
    frm.set_value('custom_one_shot_original_amount', originalAmount);

    // Apply one shot values
    frm.set_value('to_date', lastDateOfMonth);
    frm.set_value('amount', remainingAmount);
    frm.set_value('custom_one_shot_payment_date', frappe.datetime.get_today());
    frm.set_value('disabled', 0);

    frm.save('Update').then(() => {
        frappe.show_alert({
            message: __('One Shot Payment applied - {0}', [frappe.format(remainingAmount, {fieldtype: 'Currency'})]),
            indicator: 'green'
        }, 4);
        frappe.msgprint({
            title: __('One Shot Payment Applied'),
            message: `<p>✅ <b>Amount set to:</b> ${frappe.format(remainingAmount, {fieldtype: 'Currency'})}</p>
                <p>✅ <b>To Date set to:</b> ${frappe.datetime.str_to_user(lastDateOfMonth)}</p>
                <p>✅ <b>Original values stored</b> for revert</p>
                <hr>
                <p>The full remaining balance will be deducted in the next payroll run for this month.</p>`,
            indicator: 'green'
        });
    }).catch(err => {
        console.error('One Shot save error:', err);
        frappe.msgprint({
            title: __('Save Failed'),
            message: __('Failed to save One Shot Payment. The document will be reloaded.<br><br><b>Error:</b> {0}', [err.message || JSON.stringify(err) || String(err)]),
            indicator: 'red'
        });
        frm.reload_doc();
    });
}

// === REVERT ONE SHOT (WITH EDGE CASE PROTECTION) ===

async function revertOneShotPayment(frm) {
    let originalToDate = frm.doc.custom_one_shot_original_to_date;
    let originalAmount = frm.doc.custom_one_shot_original_amount;
    let hasStored = originalToDate && (originalAmount || originalAmount === 0);
    let willReDisable = checkActiveCurrentMonthSkip(frm);

    if (!hasStored) {
        frappe.msgprint({title: __('Missing Data'), message: __('Original values not found. Cannot revert automatically.'), indicator: 'red'});
        return;
    }

    // EDGE CASE: Block if document has unsaved changes
    if (frm.dirty()) {
        frappe.msgprint({
            title: __('Unsaved Changes'),
            message: __('Please save the document first before reverting One Shot Payment.'),
            indicator: 'orange'
        });
        return;
    }

    // EDGE CASE: Check if payroll was already run with the one-shot amount
    let today = new Date();
    let currentMonthCheck = [{year: today.getFullYear(), month: today.getMonth()}];

    try {
        let payrollCheck = await checkPayrollForMonths(frm.doc.employee, currentMonthCheck);

        if (payrollCheck.hasPayroll) {
            let detail = payrollCheck.details[0];
            let status = detail.docstatus === 1 ? 'Submitted' : 'Draft';
            let monthNames = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];

            frappe.msgprint({
                title: __('Cannot Revert One Shot'),
                message: `<p>Payroll already exists for <b>${monthNames[today.getMonth()]} ${today.getFullYear()}</b> with the One Shot amount.</p>
                    <p><b>Salary Slip:</b> <a href="/app/salary-slip/${detail.salarySlip}" target="_blank">${detail.salarySlip}</a> (${status})</p>
                    <p>Reverting now would cause data inconsistency.</p>
                    <p><b>Solution:</b> ${status === 'Submitted' ? 'Cancel the Salary Slip first, then revert.' : 'Delete the Draft Salary Slip first, then revert.'}</p>`,
                indicator: 'red'
            });
            return;
        }
    } catch(e) {
        console.error('Error checking payroll for revert:', e);
    }

    let reDisableWarning = willReDisable ? '<p style="color:#856404;">⚠️ Document will be re-disabled (active skip exists)</p>' : '';

    let origToDate = parseLocalDate(originalToDate);
    let pastDateWarning = '';
    if (origToDate && origToDate < today) {
        pastDateWarning = '<p style="color:#c62828;">⚠️ <b>Note:</b> The original To Date is in the past. The Additional Salary period may have already expired.</p>';
    }

    frappe.confirm(
        `<p>Revert One Shot Payment?</p>
         <p><b>Restore To Date:</b> ${frappe.datetime.str_to_user(originalToDate)}</p>
         <p><b>Restore Amount:</b> ${frappe.format(originalAmount, {fieldtype: 'Currency'})}</p>
         ${reDisableWarning}
         ${pastDateWarning}`,
        () => {
            frm.set_value('to_date', originalToDate);
            frm.set_value('amount', originalAmount);
            frm.set_value('custom_one_shot_payment_date', '');
            frm.set_value('custom_one_shot_original_to_date', '');
            frm.set_value('custom_one_shot_original_amount', 0);

            if (willReDisable) {
                frm.set_value('disabled', 1);
            }

            frm.save('Update').then(() => {
                frappe.show_alert({message: __('One Shot reverted'), indicator: 'green'}, 3);
            }).catch(err => {
                frappe.msgprint({title: __('Error'), message: err.message || JSON.stringify(err) || String(err), indicator: 'red'});
                frm.reload_doc();
            });
        }
    );
}

