frappe.ui.form.on('Employee Advance', {
    refresh: function(frm) {
        if (!frm.is_new() && frm.doc.docstatus === 1) {

            frm.add_custom_button(__('Recalculate Received'), function() {
                recalculateReceived(frm);
            }, __('Actions'));

            let paid = parseFloat(frm.doc.paid_amount) || 0;
            let received = parseFloat(frm.doc.custom_amount_received) || 0;
            let remaining = parseFloat(frm.doc.custom_remaining__amount) || 0;

            if (paid > 0) {
                let pct = Math.min(100, Math.round((received / paid) * 100));
                let color = pct >= 100 ? 'green' : (pct >= 50 ? 'blue' : (pct > 0 ? 'orange' : 'red'));

                frm.dashboard.add_indicator(
                    __('Recovered: {0} / {1} ({2}%)', [
                        frappe.format(received, {fieldtype: 'Currency'}),
                        frappe.format(paid, {fieldtype: 'Currency'}),
                        pct
                    ]), color
                );

                if (remaining > 0) {
                    frm.dashboard.add_indicator(__('Remaining: {0}', [frappe.format(remaining, {fieldtype: 'Currency'})]), 'orange');
                }
                if (pct >= 100) {
                    frm.dashboard.add_indicator(__('✓ Fully Recovered'), 'green');
                }
                if (received === 0) {
                    frm.dashboard.add_indicator(__('Awaiting First Payroll'), 'yellow');
                }

                showProgressBar(frm, paid, received);
            }

            showLinkedSalaries(frm);
        }
    },

    onload: function(frm) {
        $('.recovery-progress-bar, .linked-add-sal, .recovery-banner').remove();

        if (!frm.is_new() && frm.doc.docstatus === 1) {
            let paid = parseFloat(frm.doc.paid_amount) || 0;
            let received = parseFloat(frm.doc.custom_amount_received) || 0;
            let remaining = parseFloat(frm.doc.custom_remaining__amount) || 0;

            if (paid > 0) {
                let msg = '';
                if (received >= paid) {
                    msg = '<b style="color:green;">✓ Fully Recovered</b>';
                } else if (received > 0) {
                    msg = '<b>Recovery:</b> ' + Math.round((received/paid)*100) + '% | <b>Remaining:</b> ' + frappe.format(remaining, {fieldtype: 'Currency'});
                } else {
                    msg = '<b style="color:#856404;">⏳ No payroll deductions yet</b>';
                }

                let cls = received >= paid ? 'alert-success' : (received > 0 ? 'alert-info' : 'alert-warning');
                $(frm.fields_dict.employee.wrapper).before(
                    '<div class="recovery-banner alert ' + cls + '" style="margin:10px 0;">' + msg + '</div>'
                );
            }
        }
    }
});

function showProgressBar(frm, paid, received) {
    $('.recovery-progress-bar').remove();
    if (paid <= 0) return;

    let pct = Math.min(100, Math.round((received / paid) * 100));
    let rem = Math.max(0, paid - received);
    let clr = pct >= 100 ? '#36b37e' : (pct >= 50 ? '#2490ef' : (pct >= 25 ? '#f5a623' : '#dc3545'));

    $(frm.fields_dict.employee.wrapper).before(
        '<div class="recovery-progress-bar" style="margin:10px 15px;">' +
            '<div style="display:flex;justify-content:space-between;margin-bottom:4px;">' +
                '<small><b>Recovery Progress</b></small><small><b>' + pct + '%</b></small>' +
            '</div>' +
            '<div style="background:#e9ecef;border-radius:6px;height:10px;overflow:hidden;">' +
                '<div style="background:' + clr + ';width:' + pct + '%;height:100%;border-radius:6px;"></div>' +
            '</div>' +
            '<div style="display:flex;justify-content:space-between;margin-top:4px;">' +
                '<small style="color:#888;">Received: <b>' + frappe.format(received, {fieldtype:'Currency'}) + '</b></small>' +
                '<small style="color:#888;">' + (pct >= 100 ? '<span style="color:#36b37e;">✓ Complete</span>' : 'Remaining: <b>' + frappe.format(rem, {fieldtype:'Currency'}) + '</b>') + '</small>' +
            '</div>' +
        '</div>'
    );
}

async function recalculateReceived(frm) {
    frappe.show_alert({message: __('Scanning salary slips...'), indicator: 'blue'}, 2);

    let paid = parseFloat(frm.doc.paid_amount) || 0;
    if (paid <= 0) {
        frappe.msgprint(__('Paid amount is zero.'));
        return;
    }

    try {
        let addSalResult = await frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Additional Salary',
                filters: {
                    ref_doctype: 'Employee Advance',
                    ref_docname: frm.doc.name,
                    employee: frm.doc.employee
                },
                fields: ['name', 'salary_component'],
                limit_page_length: 0
            }
        });

        let addSalList = (addSalResult && addSalResult.message) || [];

        if (addSalList.length === 0) {
            frappe.msgprint({
                title: __('No Linked Deductions'),
                message: __('No Additional Salaries linked to this Employee Advance.'),
                indicator: 'orange'
            });
            return;
        }

        let slipResult = await frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Salary Slip',
                filters: { employee: frm.doc.employee, docstatus: 1 },
                fields: ['name', 'start_date'],
                limit_page_length: 0,
                order_by: 'start_date asc'
            }
        });

        let slips = (slipResult && slipResult.message) || [];

        let totalDeducted = 0;
        let slipCount = 0;
        let slipDetails = [];
        let seen = {};

        for (let slip of slips) {
            let slipDoc;
            try {
                let res = await frappe.call({
                    method: 'frappe.client.get',
                    args: { doctype: 'Salary Slip', name: slip.name }
                });
                slipDoc = res && res.message;
            } catch(e) {
                continue;
            }
            if (!slipDoc) continue;

            let allComps = (slipDoc.deductions || []).concat(slipDoc.earnings || []);

            for (let comp of allComps) {
                for (let addSal of addSalList) {
                    if (comp.salary_component === addSal.salary_component &&
                        comp.additional_salary === addSal.name) {

                        let key = slip.name + '_' + addSal.name + '_' + comp.idx;
                        if (seen[key]) continue;
                        seen[key] = true;

                        let amt = Math.abs(parseFloat(comp.amount) || 0);
                        totalDeducted += amt;
                        slipCount++;
                        slipDetails.push({
                            slip: slip.name,
                            date: slip.start_date,
                            component: comp.salary_component,
                            amount: amt
                        });
                    }
                }
            }
        }

        let remaining = Math.max(0, paid - totalDeducted);
        let oldReceived = parseFloat(frm.doc.custom_amount_received) || 0;
        let oldRemaining = parseFloat(frm.doc.custom_remaining__amount) || 0;
        let changed = Math.abs(oldReceived - totalDeducted) > 0.01 || Math.abs(oldRemaining - remaining) > 0.01;

        if (changed) {
            await frappe.call({
                method: 'frappe.client.set_value',
                args: {
                    doctype: 'Employee Advance',
                    name: frm.doc.name,
                    fieldname: {
                        custom_amount_received: totalDeducted,
                        custom_remaining__amount: remaining
                    }
                }
            });
            frm.reload_doc();
        }

        let detailHtml = '';
        if (slipDetails.length > 0) {
            let rows = slipDetails.map(function(s) {
                return '<tr>' +
                    '<td><a href="/app/salary-slip/' + s.slip + '" target="_blank">' + s.slip + '</a></td>' +
                    '<td>' + (s.date ? frappe.datetime.str_to_user(s.date) : '-') + '</td>' +
                    '<td>' + s.component + '</td>' +
                    '<td style="text-align:right;">' + frappe.format(s.amount, {fieldtype:'Currency'}) + '</td>' +
                '</tr>';
            }).join('');

            detailHtml = '<details style="margin:10px 0;">' +
                '<summary style="cursor:pointer;color:#5e64ff;"><b>View ' + slipCount + ' Deduction(s)</b></summary>' +
                '<table style="width:100%;margin-top:5px;font-size:11px;" border="1" cellpadding="4" cellspacing="0">' +
                    '<thead style="background:#f5f7fa;"><tr><th>Salary Slip</th><th>Period</th><th>Component</th><th style="text-align:right;">Amount</th></tr></thead>' +
                    '<tbody>' + rows + '</tbody>' +
                    '<tfoot style="background:#f5f7fa;font-weight:bold;"><tr><td colspan="3">Total</td><td style="text-align:right;">' + frappe.format(totalDeducted, {fieldtype:'Currency'}) + '</td></tr></tfoot>' +
                '</table>' +
            '</details>';
        } else {
            detailHtml = '<p style="color:#856404;"><i>No submitted salary slips with deductions found.</i></p>';
        }

        let pct = paid > 0 ? Math.round((totalDeducted / paid) * 100) : 0;

        frappe.msgprint({
            title: __('Recalculation Complete'),
            message: '<table style="width:100%;margin:10px 0;">' +
                '<tr><td style="padding:5px;">Paid Amount:</td><td style="padding:5px;"><b>' + frappe.format(paid, {fieldtype:'Currency'}) + '</b></td></tr>' +
                '<tr><td style="padding:5px;">Recovered (' + slipCount + ' slips):</td><td style="padding:5px;"><b style="color:green;">' + frappe.format(totalDeducted, {fieldtype:'Currency'}) + '</b> (' + pct + '%)</td></tr>' +
                '<tr style="border-top:2px solid #333;"><td style="padding:5px;"><b>Remaining:</b></td><td style="padding:5px;"><b style="color:' + (remaining > 0 ? '#c62828' : '#36b37e') + ';">' + frappe.format(remaining, {fieldtype:'Currency'}) + '</b>' + (remaining <= 0 ? ' ✓' : '') + '</td></tr>' +
            '</table>' +
            (changed ? 
                '<div style="padding:8px;background:#e8f5e9;border-left:3px solid #36b37e;border-radius:4px;margin:10px 0;">' +
                    '<b>🔄 Updated:</b><br>' +
                    'Received: ' + frappe.format(oldReceived, {fieldtype:'Currency'}) + ' → <b>' + frappe.format(totalDeducted, {fieldtype:'Currency'}) + '</b><br>' +
                    'Remaining: ' + frappe.format(oldRemaining, {fieldtype:'Currency'}) + ' → <b>' + frappe.format(remaining, {fieldtype:'Currency'}) + '</b>' +
                '</div>' :
                '<p style="color:green;">✅ Already correct.</p>'
            ) + detailHtml,
            indicator: changed ? 'blue' : 'green'
        });

    } catch(err) {
        console.error('Error:', err);
        frappe.msgprint({
            title: __('Error'),
            message: err.message || JSON.stringify(err) || String(err),
            indicator: 'red'
        });
    }
}

async function showLinkedSalaries(frm) {
    $('.linked-add-sal').remove();

    try {
        let result = await frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Additional Salary',
                filters: {
                    ref_doctype: 'Employee Advance',
                    ref_docname: frm.doc.name,
                    employee: frm.doc.employee
                },
                fields: ['name', 'salary_component', 'amount', 'from_date', 'to_date',
                         'disabled', 'docstatus', 'custom_one_shot_payment_date',
                         'custom_times_skipped', 'custom_total_months_skipped'],
                limit_page_length: 0
            }
        });

        let list = (result && result.message) || [];
        if (list.length === 0) return;

        let rows = list.map(function(a) {
            let badge = '';
            if (a.docstatus === 2) badge = '<span class="badge" style="background:#dc3545;color:#fff;font-size:10px;">Cancelled</span>';
            else if (a.custom_one_shot_payment_date) badge = '<span class="badge" style="background:#2490ef;color:#fff;font-size:10px;">One Shot</span>';
            else if (a.disabled) badge = '<span class="badge" style="background:#ffc107;color:#333;font-size:10px;">Disabled</span>';
            else badge = '<span class="badge" style="background:#36b37e;color:#fff;font-size:10px;">Active</span>';

            let skip = a.custom_times_skipped > 0 ? '<br><small style="color:#856404;">Skipped ' + (a.custom_total_months_skipped || 0) + 'm</small>' : '';

            return '<tr>' +
                '<td><a href="/app/additional-salary/' + a.name + '" target="_blank">' + a.name + '</a></td>' +
                '<td>' + a.salary_component + '</td>' +
                '<td style="text-align:right;">' + frappe.format(Math.abs(a.amount), {fieldtype:'Currency'}) + '/mo</td>' +
                '<td>' + frappe.datetime.str_to_user(a.from_date) + ' → ' + frappe.datetime.str_to_user(a.to_date) + '</td>' +
                '<td>' + badge + skip + '</td>' +
            '</tr>';
        }).join('');

        $(frm.fields_dict.employee.wrapper).before(
            '<div class="linked-add-sal" style="margin:15px;">' +
                '<h6 style="margin-bottom:8px;"><b>📋 Linked Deductions (' + list.length + ')</b></h6>' +
                '<table class="table table-bordered" style="font-size:12px;margin-bottom:0;">' +
                    '<thead style="background:#f5f7fa;"><tr><th>Name</th><th>Component</th><th style="text-align:right;">Monthly</th><th>Period</th><th>Status</th></tr></thead>' +
                    '<tbody>' + rows + '</tbody>' +
                '</table>' +
            '</div>'
        );
    } catch(e) {
        console.warn('Error:', e);
    }
}
